  RETURN 'Notes de frais';
END;
$function$;
COMMENT ON FUNCTION expense.brand() IS 'Brand label for Expense module';

CREATE OR REPLACE FUNCTION expense.get_categories()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN SELECT id, nom, code_comptable FROM expense.categorie ORDER BY nom LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.nom),
      coalesce(pgv.esc(r.code_comptable), '—')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    RETURN pgv.empty('Aucune catégorie');
  END IF;

  RETURN pgv.md_table(ARRAY['Catégorie', 'Code comptable'], v_rows);
END;
$function$;
COMMENT ON FUNCTION expense.get_categories() IS 'Liste des catégories de frais';

CREATE OR REPLACE FUNCTION expense.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_nb_notes int;
  v_total_en_cours numeric(12,2);
  v_montant_moyen numeric(12,2);
  v_nb_a_valider int;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT count(*)::int INTO v_nb_notes FROM expense.note;

  SELECT coalesce(sum(l.montant_ttc), 0)
    INTO v_total_en_cours
    FROM expense.note n
    JOIN expense.ligne l ON l.note_id = n.id
   WHERE n.statut IN ('brouillon', 'soumise', 'validee');

  SELECT coalesce(avg(sub.total), 0)
    INTO v_montant_moyen
    FROM (
      SELECT sum(l.montant_ttc) AS total
        FROM expense.ligne l
       GROUP BY l.note_id
    ) sub;

  SELECT count(*)::int INTO v_nb_a_valider
    FROM expense.note WHERE statut = 'soumise';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Notes de frais', v_nb_notes::text),
    pgv.stat('Total en cours', to_char(v_total_en_cours, 'FM999 990.00') || ' EUR'),
    pgv.stat('Montant moyen', to_char(v_montant_moyen, 'FM999 990.00') || ' EUR'),
    pgv.stat('A valider', v_nb_a_valider::text)
  ]);

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT n.id, n.reference, n.auteur, n.statut, n.date_debut, n.date_fin,
           coalesce(sum(l.montant_ttc), 0) AS total_ttc,
           count(l.id)::int AS nb_lignes
      FROM expense.note n
      LEFT JOIN expense.ligne l ON l.note_id = n.id
     GROUP BY n.id
     ORDER BY n.created_at DESC LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_note', jsonb_build_object('p_id', r.id)), pgv.esc(coalesce(r.reference, '#' || r.id))),
      pgv.esc(r.auteur),
      to_char(r.date_debut, 'DD/MM') || ' - ' || to_char(r.date_fin, 'DD/MM/YYYY'),
      r.nb_lignes || ' ligne(s)',
      expense._statut_badge(r.statut),
      to_char(r.total_ttc, 'FM999 990.00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune note de frais', 'Créez votre première note pour commencer.');
  ELSE
    v_body := v_body || pgv.md_table(ARRAY['Référence', 'Auteur', 'Période', 'Lignes', 'Statut', 'Total TTC'], v_rows);
  END IF;

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouvelle note</a>', pgv.call_ref('get_note_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION expense.get_index() IS 'Dashboard expense : stats KPI + notes récentes';

CREATE OR REPLACE FUNCTION expense.get_ligne_form(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_note_id int := (p_params->>'note_id')::int;
  v_cat_options jsonb;
  v_body text;
BEGIN
  IF v_note_id IS NULL THEN
    RETURN pgv.error('400', 'note_id requis');
  END IF;

  -- Build category options
  SELECT jsonb_agg(jsonb_build_object('value', id::text, 'label', nom) ORDER BY nom)
    INTO v_cat_options
    FROM expense.categorie;

  v_cat_options := coalesce(v_cat_options, '[]'::jsonb);

  v_body := '<form data-rpc="post_ligne_ajouter">'
    || '<input type="hidden" name="note_id" value="' || v_note_id || '">'
    || pgv.input('date_depense', 'date', 'Date', to_char(now()::date, 'YYYY-MM-DD'), true)
    || pgv.sel('categorie_id', 'Catégorie', v_cat_options)
    || pgv.input('description', 'text', 'Description', NULL, true)
    || '<div class="pgv-grid">'
    || pgv.input('montant_ht', 'number', 'Montant HT', NULL, true)
    || pgv.input('tva', 'number', 'TVA', '0')
    || pgv.input('km', 'number', 'Km (si déplacement)')
    || '</div>'
    || '<button type="submit">Ajouter la ligne</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION expense.get_ligne_form(jsonb) IS 'Formulaire ajout ligne de dépense';

CREATE OR REPLACE FUNCTION expense.get_note(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_note record;
  v_body text;
  v_rows text[];
  v_total_ht numeric(12,2);
  v_total_tva numeric(12,2);
  v_total_ttc numeric(12,2);
  r record;
BEGIN
  IF p_id IS NULL THEN
    RETURN pgv.error('400', 'ID requis', 'Spécifiez un identifiant de note.');
  END IF;

  SELECT * INTO v_note FROM expense.note WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.error('404', 'Note introuvable', 'La note #' || p_id || ' n''existe pas.');
  END IF;

  -- En-tête
  v_body := pgv.dl(VARIADIC ARRAY[
    'Référence', coalesce(v_note.reference, '#' || v_note.id),
    'Auteur', pgv.esc(v_note.auteur),
    'Période', to_char(v_note.date_debut, 'DD/MM/YYYY') || ' - ' || to_char(v_note.date_fin, 'DD/MM/YYYY'),
    'Statut', expense._statut_badge(v_note.statut),
    'Commentaire', coalesce(pgv.esc(v_note.commentaire), '—')
  ]);

  -- Lignes
  v_rows := ARRAY[]::text[];
  v_total_ht := 0; v_total_tva := 0; v_total_ttc := 0;

  FOR r IN
    SELECT l.id, l.date_depense, c.nom AS categorie, l.description,
           l.montant_ht, l.tva, l.montant_ttc, l.km
      FROM expense.ligne l
      LEFT JOIN expense.categorie c ON c.id = l.categorie_id
     WHERE l.note_id = p_id
     ORDER BY l.date_depense, l.id
  LOOP
    v_total_ht := v_total_ht + r.montant_ht;
    v_total_tva := v_total_tva + r.tva;
    v_total_ttc := v_total_ttc + r.montant_ttc;

    v_rows := v_rows || ARRAY[
      to_char(r.date_depense, 'DD/MM/YYYY'),
      pgv.esc(coalesce(r.categorie, '—')),
      pgv.esc(r.description),
      CASE WHEN r.km IS NOT NULL THEN r.km || ' km' ELSE '—' END,
      to_char(r.montant_ht, 'FM999 990.00'),
      to_char(r.tva, 'FM999 990.00'),
      '<strong>' || to_char(r.montant_ttc, 'FM999 990.00') || '</strong>'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne', 'Ajoutez des dépenses à cette note.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Date', 'Catégorie', 'Description', 'Km', 'HT', 'TVA', 'TTC'],
      v_rows
    );
    -- Totaux
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.stat('Total HT', to_char(v_total_ht, 'FM999 990.00') || ' EUR'),
      pgv.stat('Total TVA', to_char(v_total_tva, 'FM999 990.00') || ' EUR'),
      pgv.stat('Total TTC', to_char(v_total_ttc, 'FM999 990.00') || ' EUR')
    ]);
  END IF;

  -- Actions selon statut
  v_body := v_body || '<p>';

  IF v_note.statut = 'brouillon' THEN
    v_body := v_body
      || pgv.action('post_ligne_ajouter', 'Ajouter une ligne',
           jsonb_build_object('note_id', p_id),
           NULL, 'primary')
      || ' '
      || pgv.action('post_note_soumettre', 'Soumettre',
           jsonb_build_object('id', p_id),
           'Soumettre cette note pour validation ?', 'outline');
  ELSIF v_note.statut = 'soumise' THEN
    v_body := v_body
      || pgv.action('post_note_valider', 'Valider',
           jsonb_build_object('id', p_id),
           'Valider cette note de frais ?', 'primary')
      || ' '
      || pgv.action('post_note_rejeter', 'Rejeter',
           jsonb_build_object('id', p_id),
           'Rejeter cette note de frais ?', 'danger');
  ELSIF v_note.statut = 'validee' THEN
    v_body := v_body
      || pgv.action('post_note_rembourser', 'Rembourser',
           jsonb_build_object('id', p_id),
           'Marquer cette note comme remboursée ?', 'primary');
  END IF;

  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION expense.get_note(integer) IS 'Détail note de frais : infos, lignes, totaux, workflow';

CREATE OR REPLACE FUNCTION expense.get_note_form(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
  v_note record;
  v_body text;
BEGIN
  IF v_id IS NOT NULL THEN
    SELECT * INTO v_note FROM expense.note WHERE id = v_id;
    IF NOT FOUND THEN
      RETURN pgv.error('404', 'Note introuvable');
    END IF;
    IF v_note.statut <> 'brouillon' THEN
      RETURN pgv.error('400', 'Modification impossible', 'Seules les notes en brouillon peuvent être modifiées.');
    END IF;
  END IF;

  v_body := '<form data-rpc="post_note_creer">';

  IF v_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || v_id || '">';
  END IF;

  v_body := v_body
    || pgv.input('auteur', 'text', 'Auteur', v_note.auteur, true)
    || '<div class="pgv-grid">'
    || pgv.input('date_debut', 'date', 'Date début', CASE WHEN v_note IS NOT NULL THEN to_char(v_note.date_debut, 'YYYY-MM-DD') ELSE to_char(date_trunc('month', now()), 'YYYY-MM-DD') END, true)
    || pgv.input('date_fin', 'date', 'Date fin', CASE WHEN v_note IS NOT NULL THEN to_char(v_note.date_fin, 'YYYY-MM-DD') ELSE to_char(now()::date, 'YYYY-MM-DD') END, true)
    || '</div>'
    || pgv.textarea('commentaire', 'Commentaire', v_note.commentaire)
    || '<button type="submit">' || CASE WHEN v_id IS NOT NULL THEN 'Modifier' ELSE 'Créer la note' END || '</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION expense.get_note_form(jsonb) IS 'Formulaire création/édition note de frais';

CREATE OR REPLACE FUNCTION expense.get_notes(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_statut text := p_params->>'statut';
  v_auteur text := p_params->>'auteur';
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_body := '<form action="/notes" method="get">'
    || '<fieldset role="group">'
    || pgv.sel('statut', 'Statut', '[{"value":"","label":"Tous"},{"value":"brouillon","label":"Brouillon"},{"value":"soumise","label":"Soumise"},{"value":"validee","label":"Validée"},{"value":"remboursee","label":"Remboursée"},{"value":"rejetee","label":"Rejetée"}]'::jsonb, v_statut)
    || pgv.input('auteur', 'text', 'Auteur', v_auteur)
    || '</fieldset>'
    || '<button type="submit">Filtrer</button>'
    || '</form>';

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT n.id, n.reference, n.auteur, n.statut, n.date_debut, n.date_fin,
           coalesce(sum(l.montant_ttc), 0) AS total_ttc,
           count(l.id)::int AS nb_lignes
      FROM expense.note n
      LEFT JOIN expense.ligne l ON l.note_id = n.id
     WHERE (v_statut IS NULL OR n.statut = v_statut)
       AND (v_auteur IS NULL OR n.auteur ILIKE '%' || v_auteur || '%')
     GROUP BY n.id
     ORDER BY n.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_note', jsonb_build_object('p_id', r.id)), pgv.esc(coalesce(r.reference, '#' || r.id))),
      pgv.esc(r.auteur),
      to_char(r.date_debut, 'DD/MM') || ' - ' || to_char(r.date_fin, 'DD/MM/YYYY'),
      r.nb_lignes || ' ligne(s)',
      expense._statut_badge(r.statut),
      to_char(r.total_ttc, 'FM999 990.00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune note trouvée');
  ELSE
    v_body := v_body || pgv.md_table(ARRAY['Référence', 'Auteur', 'Période', 'Lignes', 'Statut', 'Total TTC'], v_rows, 15);
  END IF;

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouvelle note</a>', pgv.call_ref('get_note_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION expense.get_notes(jsonb) IS 'Liste filtrée des notes de frais par statut et auteur';

