CREATE OR REPLACE FUNCTION expense.post_ligne_ajouter(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_note_id int := (p_params->>'note_id')::int;
  v_date date := (p_params->>'date_depense')::date;
  v_categorie_id int := (p_params->>'categorie_id')::int;
  v_description text := p_params->>'description';
  v_montant_ht numeric(12,2) := (p_params->>'montant_ht')::numeric;
  v_tva numeric(12,2) := coalesce((p_params->>'tva')::numeric, 0);
  v_km numeric(8,1) := (p_params->>'km')::numeric;
  v_statut text;
BEGIN
  IF v_note_id IS NULL OR v_date IS NULL OR v_description IS NULL OR v_montant_ht IS NULL THEN
    RETURN '<template data-toast="error">Note, date, description et montant HT requis.</template>';
  END IF;

  SELECT statut INTO v_statut FROM expense.note WHERE id = v_note_id;
  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Note introuvable.</template>';
  END IF;
  IF v_statut <> 'brouillon' THEN
    RETURN '<template data-toast="error">Ajout impossible : la note n''est plus en brouillon.</template>';
  END IF;

  INSERT INTO expense.ligne (note_id, date_depense, categorie_id, description, montant_ht, tva, km)
  VALUES (v_note_id, v_date, v_categorie_id, v_description, v_montant_ht, v_tva, v_km);

  RETURN '<template data-toast="success">Ligne ajoutée.</template>'
    || '<template data-redirect="/note?p_id=' || v_note_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_ligne_ajouter(jsonb) IS 'Ajouter une ligne de dépense à une note (brouillon uniquement)';

CREATE OR REPLACE FUNCTION expense.post_note_creer(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
  v_auteur text := p_params->>'auteur';
  v_date_debut date := (p_params->>'date_debut')::date;
  v_date_fin date := (p_params->>'date_fin')::date;
  v_commentaire text := p_params->>'commentaire';
  v_note_id int;
BEGIN
  IF v_auteur IS NULL OR v_date_debut IS NULL OR v_date_fin IS NULL THEN
    RETURN '<template data-toast="error">Auteur, date début et date fin sont requis.</template>';
  END IF;

  IF v_date_fin < v_date_debut THEN
    RETURN '<template data-toast="error">La date de fin doit être postérieure à la date de début.</template>';
  END IF;

  IF v_id IS NOT NULL THEN
    UPDATE expense.note
       SET auteur = v_auteur,
           date_debut = v_date_debut,
           date_fin = v_date_fin,
           commentaire = v_commentaire,
           updated_at = now()
     WHERE id = v_id AND statut = 'brouillon';

    IF NOT FOUND THEN
      RETURN '<template data-toast="error">Note introuvable ou non modifiable.</template>';
    END IF;
    v_note_id := v_id;
  ELSE
    INSERT INTO expense.note (reference, auteur, date_debut, date_fin, commentaire)
    VALUES (expense._next_numero(), v_auteur, v_date_debut, v_date_fin, v_commentaire)
    RETURNING id INTO v_note_id;
  END IF;

  RETURN '<template data-toast="success">Note ' || CASE WHEN v_id IS NOT NULL THEN 'modifiée' ELSE 'créée' END || '.</template>'
    || '<template data-redirect="/note?p_id=' || v_note_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_note_creer(jsonb) IS 'Créer ou modifier une note de frais (brouillon)';

CREATE OR REPLACE FUNCTION expense.post_note_rejeter(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
BEGIN
  IF v_id IS NULL THEN
    RETURN '<template data-toast="error">ID requis.</template>';
  END IF;

  UPDATE expense.note SET statut = 'rejetee', updated_at = now()
   WHERE id = v_id AND statut = 'soumise';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Note introuvable ou pas en statut soumise.</template>';
  END IF;

  RETURN '<template data-toast="success">Note rejetée.</template>'
    || '<template data-redirect="/note?p_id=' || v_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_note_rejeter(jsonb) IS 'Rejeter une note soumise';

CREATE OR REPLACE FUNCTION expense.post_note_rembourser(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
  v_note record;
  v_total_ttc numeric(12,2);
  v_has_ledger boolean;
BEGIN
  IF v_id IS NULL THEN
    RETURN '<template data-toast="error">ID requis.</template>';
  END IF;

  SELECT * INTO v_note FROM expense.note WHERE id = v_id AND statut = 'validee';
  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Note introuvable ou pas en statut validée.</template>';
  END IF;

  SELECT coalesce(sum(montant_ttc), 0) INTO v_total_ttc FROM expense.ligne WHERE note_id = v_id;

  UPDATE expense.note SET statut = 'remboursee', updated_at = now() WHERE id = v_id;

  SELECT EXISTS(SELECT 1 FROM pg_namespace WHERE nspname = 'ledger') INTO v_has_ledger;
  IF v_has_ledger THEN
    BEGIN
      EXECUTE format(
        'SELECT ledger.post_ecriture_creer(%L::jsonb)',
        jsonb_build_object(
          'journal', 'NDF',
          'libelle', 'Remboursement ' || coalesce(v_note.reference, '#' || v_id),
          'lignes', jsonb_build_array(
            jsonb_build_object('compte', '625000', 'debit', v_total_ttc, 'credit', 0),
            jsonb_build_object('compte', '421000', 'debit', 0, 'credit', v_total_ttc)
          )
        )::text
      );
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END IF;

  RETURN '<template data-toast="success">Note remboursée (' || to_char(v_total_ttc, 'FM999 990.00') || ' EUR).</template>'
    || '<template data-redirect="/note?p_id=' || v_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_note_rembourser(jsonb) IS 'Rembourser une note validée (+ écriture ledger si disponible)';

CREATE OR REPLACE FUNCTION expense.post_note_soumettre(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
  v_nb_lignes int;
BEGIN
  IF v_id IS NULL THEN
    RETURN '<template data-toast="error">ID requis.</template>';
  END IF;

  SELECT count(*)::int INTO v_nb_lignes FROM expense.ligne WHERE note_id = v_id;
  IF v_nb_lignes = 0 THEN
    RETURN '<template data-toast="error">Impossible de soumettre une note sans ligne.</template>';
  END IF;

  UPDATE expense.note SET statut = 'soumise', updated_at = now()
   WHERE id = v_id AND statut = 'brouillon';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Note introuvable ou pas en brouillon.</template>';
  END IF;

  RETURN '<template data-toast="success">Note soumise pour validation.</template>'
    || '<template data-redirect="/note?p_id=' || v_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_note_soumettre(jsonb) IS 'Passer une note brouillon -> soumise (guard: au moins 1 ligne)';

CREATE OR REPLACE FUNCTION expense.post_note_valider(p_params jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_params->>'id')::int;
BEGIN
  IF v_id IS NULL THEN
    RETURN '<template data-toast="error">ID requis.</template>';
  END IF;

  UPDATE expense.note SET statut = 'validee', updated_at = now()
   WHERE id = v_id AND statut = 'soumise';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Note introuvable ou pas en statut soumise.</template>';
  END IF;

  RETURN '<template data-toast="success">Note validée.</template>'
    || '<template data-redirect="/note?p_id=' || v_id || '"></template>';
END;
$function$;
COMMENT ON FUNCTION expense.post_note_valider(jsonb) IS 'Passer une note soumise -> validée';

GRANT USAGE ON SCHEMA expense TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA expense TO web_anon;

-- Schema: expense_ut
CREATE SCHEMA IF NOT EXISTS expense_ut;

CREATE OR REPLACE FUNCTION expense_ut.test_next_numero()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ref1 text;
  v_ref2 text;
  v_year text := to_char(now(), 'YYYY');
  v_res text;
BEGIN
  -- Clean
  DELETE FROM expense.ligne;
  DELETE FROM expense.note;

  -- Create first note -> should get NDF-YYYY-001
  v_res := expense.post_note_creer('{"auteur":"Test","date_debut":"2026-03-01","date_fin":"2026-03-31"}'::jsonb);
  SELECT reference INTO v_ref1 FROM expense.note ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_ref1, 'NDF-' || v_year || '-001', 'first note gets NDF-YYYY-001');

  -- Create second note -> should get NDF-YYYY-002
  v_res := expense.post_note_creer('{"auteur":"Test","date_debut":"2026-03-01","date_fin":"2026-03-31"}'::jsonb);
  SELECT reference INTO v_ref2 FROM expense.note ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_ref2, 'NDF-' || v_year || '-002', 'second note gets NDF-YYYY-002');

  -- Cleanup
  DELETE FROM expense.ligne;
  DELETE FROM expense.note;
END;
$function$;
COMMENT ON FUNCTION expense_ut.test_next_numero() IS 'Test numérotation séquentielle via post_note_creer';

CREATE OR REPLACE FUNCTION expense_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- brand
  v_html := expense.brand();
  RETURN NEXT ok(v_html = 'Notes de frais', 'brand returns label');

  -- nav_items
  RETURN NEXT ok(expense.nav_items() IS NOT NULL, 'nav_items returns jsonb');

  -- get_index (empty)
  v_html := expense.get_index();
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'index has stats');
  RETURN NEXT ok(v_html LIKE '%Aucune note%' OR v_html LIKE '%md%', 'index has empty or table');

  -- get_notes
  v_html := expense.get_notes();
  RETURN NEXT ok(v_html IS NOT NULL, 'get_notes renders');

  -- get_categories
  v_html := expense.get_categories();
  RETURN NEXT ok(v_html LIKE '%Repas%', 'categories lists Repas');

  -- get_note_form
  v_html := expense.get_note_form();
  RETURN NEXT ok(v_html LIKE '%post_note_creer%', 'note_form has rpc');

  -- get_note 404
  v_html := expense.get_note(999999);
  RETURN NEXT ok(v_html LIKE '%introuvable%', 'get_note 404');
END;
$function$;
COMMENT ON FUNCTION expense_ut.test_pages_render() IS 'Test rendu des pages expense (smoke test)';

CREATE OR REPLACE FUNCTION expense_ut.test_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_note_id int;
  v_res text;
  v_statut text;
BEGIN
  -- Clean
  DELETE FROM expense.ligne;
  DELETE FROM expense.note;

  -- Create note
  v_res := expense.post_note_creer('{"auteur":"Alice","date_debut":"2026-03-01","date_fin":"2026-03-31"}'::jsonb);
  RETURN NEXT ok(v_res LIKE '%data-toast="success"%', 'note created');
  SELECT id INTO v_note_id FROM expense.note ORDER BY id DESC LIMIT 1;

  -- Submit without lines -> fail
  v_res := expense.post_note_soumettre(jsonb_build_object('id', v_note_id));
  RETURN NEXT ok(v_res LIKE '%sans ligne%', 'cannot submit without lines');

  -- Add line
  v_res := expense.post_ligne_ajouter(jsonb_build_object(
    'note_id', v_note_id, 'date_depense', '2026-03-05',
    'description', 'Repas client', 'montant_ht', 25.00, 'tva', 5.00,
    'categorie_id', (SELECT id FROM expense.categorie WHERE nom = 'Repas')
  ));
  RETURN NEXT ok(v_res LIKE '%Ligne ajoutée%', 'line added');

  -- Submit
  v_res := expense.post_note_soumettre(jsonb_build_object('id', v_note_id));
  RETURN NEXT ok(v_res LIKE '%soumise%', 'note submitted');
  SELECT statut INTO v_statut FROM expense.note WHERE id = v_note_id;
  RETURN NEXT is(v_statut, 'soumise', 'statut is soumise');

  -- Cannot add line after submit
  v_res := expense.post_ligne_ajouter(jsonb_build_object(
    'note_id', v_note_id, 'date_depense', '2026-03-06',
    'description', 'Should fail', 'montant_ht', 10.00
  ));
  RETURN NEXT ok(v_res LIKE '%brouillon%', 'cannot add line to submitted note');

  -- Validate
  v_res := expense.post_note_valider(jsonb_build_object('id', v_note_id));
  RETURN NEXT ok(v_res LIKE '%validée%', 'note validated');
  SELECT statut INTO v_statut FROM expense.note WHERE id = v_note_id;
  RETURN NEXT is(v_statut, 'validee', 'statut is validee');

  -- Reimburse
  v_res := expense.post_note_rembourser(jsonb_build_object('id', v_note_id));
  RETURN NEXT ok(v_res LIKE '%remboursée%', 'note reimbursed');
  SELECT statut INTO v_statut FROM expense.note WHERE id = v_note_id;
  RETURN NEXT is(v_statut, 'remboursee', 'statut is remboursee');

  -- Cleanup
  DELETE FROM expense.ligne WHERE note_id = v_note_id;
  DELETE FROM expense.note WHERE id = v_note_id;
END;
$function$;
COMMENT ON FUNCTION expense_ut.test_workflow() IS 'Test workflow complet : brouillon -> soumise -> validée -> remboursée';

GRANT USAGE ON SCHEMA expense_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA expense_ut TO web_anon;

